import java.io.*;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        try {
            // Use a whitelist approach to only allow specific classes to be deserialized
            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(Base64.getDecoder().decode(userInput)));
            Object obj = ois.readObject();

            // Perform type checking on the deserialized object
            if (obj instanceof SomeClass) {
                SomeClass deserializedObject = (SomeClass) obj;
                // Do something with the deserialized object
                System.out.println("Deserialized object: " + deserializedObject.toString());
            } else {
                System.out.println("Invalid object type");
            }

        } catch (IOException | ClassNotFoundException | ClassCastException e) {
            e.printStackTrace();
        }
    }
}

